import Stripe from 'stripe';
import { createClient } from '@supabase/supabase-js';

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!);
const supabase = createClient(process.env.SUPABASE_URL!, process.env.SUPABASE_SERVICE_ROLE_KEY!);

export async function POST(req: Request) {
  const body = await req.text();
  const sig = req.headers.get('stripe-signature')!;
  const event = stripe.webhooks.constructEvent(JSON.stringify(body), sig, process.env.STRIPE_WEBHOOK_SECRET!);
  await supabase.from('webhook_events').insert({ event_id: event.id, event_type: event.type, payload: event });
  return new Response('ok');
}

const { error } = await supabase.from('webhook_events').insert({ event_id: event.id, event_type: event.type, payload: event });
if (error) {
  console.error('webhook insert failed', error);
  return new Response('insert failed', { status: 500 });
}
return new Response('ok');

const { error } = await supabase.from('webhook_events').upsert(
  { event_id: event.id, event_type: event.type, payload: event },
  { onConflict: 'event_id', ignoreDuplicates: true },
);

